// ── Mapeo de columnas del Excel a campos de la BD ────────────────────────────
// Ajusta los nombres de columna si difieren en tu Excel
const items = $input.all();
const procesos = [];
const kpis = [];

for (const item of items) {
  const row = item.json;

  // Saltar filas vacías o de ejemplo
  const codigo = (row['Código'] || row['codigo'] || '').toString().trim();
  if (!codigo || codigo.startsWith('[') || codigo === 'Código') continue;

  // ── Mapear tipo ────────────────────────────────────────────────────────────
  const tipoRaw = (row['Tipo de Proceso'] || row['tipo'] || '').trim();
  const tipo = tipoRaw.includes('Estrat') ? 'Estratégico'
             : tipoRaw.includes('Operac') ? 'Operacional'
             : 'Complementario';

  // ── Mapear costo ───────────────────────────────────────────────────────────
  const parseCosto = (v) => {
    if (!v) return 0;
    const n = parseInt(String(v).replace(/[^0-9]/g, ''));
    return isNaN(n) ? 0 : n;
  };

  // ── Mapear fecha ───────────────────────────────────────────────────────────
  const parseDate = (v) => {
    if (!v) return null;
    const s = String(v).trim();
    if (!s || s.startsWith('[')) return null;
    // Intentar varios formatos
    const parts = s.split(/[/\-.]/)
    if (parts.length === 3) {
      // DD/MM/YYYY
      const [d, m, y] = parts;
      const date = new Date(`${y}-${m.padStart(2,'0')}-${d.padStart(2,'0')}`);
      if (!isNaN(date)) return date.toISOString().split('T')[0];
    }
    const date = new Date(v);
    if (!isNaN(date)) return date.toISOString().split('T')[0];
    return null;
  };

  // ── Parsear sucesores (columna puede ser 'PO-01, PO-02' o JSON) ───────────
  const parseSucesores = (v) => {
    if (!v) return JSON.stringify([]);
    const s = String(v).trim();
    try { JSON.parse(s); return s; } catch {}
    // Viene como 'PO-01, PO-02, PC-03'
    const arr = s.split(',').map(x => x.trim()).filter(Boolean);
    return JSON.stringify(arr);
  };

  // ── Normalizar aprobación ────────────────────────────────────────────────
  const aprobRaw = (row['Estado de Aprobación'] || row['aprobacion'] || '').trim();
  const aprobMap = {
    'aprobado': 'Aprobado',
    'pendiente de aprobar': 'Pendiente de Aprobar',
    'borrador': 'Borrador',
  };
  const aprobacion = aprobMap[aprobRaw.toLowerCase()] || 'Borrador';

  // ── Construir objeto proceso ──────────────────────────────────────────────
  const proceso = {
    id:                codigo,
    nombre:            (row['Nombre del Proceso'] || row['nombre'] || '').trim(),
    macroproceso:      (row['Macroproceso'] || row['macroproceso'] || '').trim(),
    tipo,
    descripcion:       (row['Descripción / Propósito'] || row['descripcion'] || '').trim(),
    funcion_arq:       (row['Función en la Arquitectura'] || row['funcion_arq'] || '').trim(),
    owner:             (row['Process Owner'] || row['owner'] || '').trim(),
    area:              (row['Área / Departamento'] || row['area'] || '').trim(),
    equipo:            (row['Equipo Involucrado'] || row['equipo'] || '').trim(),
    entradas:          (row['Entradas (Inputs)'] || row['entradas'] || '').trim(),
    salidas:           (row['Salidas (Outputs)'] || row['salidas'] || '').trim(),
    proveedores:       (row['Proveedores del Proceso'] || row['proveedores'] || '').trim(),
    clientes:          (row['Clientes del Proceso'] || row['clientes'] || '').trim(),
    predecesores:      (row['Procesos Predecesores'] || row['pred'] || '').trim(),
    sucesores:         parseSucesores(row['Procesos Sucesores'] || row['suc'] || ''),
    n_alimenta:        parseInt(row['N° Procesos que Alimenta'] || row['n_alimenta'] || 0) || 0,
    criticidad:        parseInt(row['Criticidad (1-5)'] || row['criticidad'] || 1) || 1,
    nivel_riesgo:      (row['Nivel de Riesgo'] || row['nivel_riesgo'] || 'BAJO').trim(),
    impacto_fallo:     (row['Impacto si Falla'] || row['impacto_fallo'] || '').trim(),
    procesos_bloq:     (row['Procesos Bloqueados'] || row['proc_bloq'] || '').trim(),
    tipo_costo:        (row['Tipo de Costo de Fallo'] || row['tipo_costo'] || '').trim(),
    costo_min:         parseCosto(row['Costo Mín. Estimado ($)'] || row['costo_min']),
    costo_max:         parseCosto(row['Costo Máx. Estimado ($)'] || row['costo_max']),
    probabilidad:      (row['Probabilidad de Fallo'] || row['probabilidad'] || 'Baja').trim(),
    prioridad:         parseInt(row['Prioridad de Atención'] || row['prioridad'] || 3) || 3,
    accion_prev:       (row['Acción Preventiva'] || row['accion_prev'] || '').trim(),
    estado:            (row['Estado del Proceso'] || row['estado'] || 'Activo').trim(),
    aprobacion,
    aprobador:         (row['Responsable de Firma'] || row['aprobador'] || '').trim(),
    fecha_aprobacion:  parseDate(row['Fecha de Aprobación'] || row['fecha_aprobacion']),
    version_aprobada:  (row['N° Versión Aprobada'] || row['version_aprobada'] || '').trim(),
    madurez:           parseInt(row['Nivel de Madurez (1-5)'] || row['madurez'] || 1) || 1,
    frecuencia:        (row['Frecuencia de Ejecución'] || row['frecuencia'] || '').trim(),
    normativa:         (row['Normativa / Estándar'] || row['normativa'] || '').trim(),
    herramientas:      (row['Herramientas / Sistemas'] || row['herramientas'] || '').trim(),
    link_procedimiento:(row['🔗 Enlace al Procedimiento'] || row['link_proc'] || '').trim(),
    link_flujograma:   (row['🔗 Enlace al Flujograma'] || row['link_flujo'] || '').trim(),
    version_doc:       (row['Versión del Doc.'] || row['version'] || '').trim(),
    fecha_revision:    parseDate(row['Fecha Última Revisión'] || row['fecha_rev']),
    fecha_prox_rev:    parseDate(row['Fecha Próxima Revisión'] || row['fecha_prox']),
    resp_revision:     (row['Responsable de Revisión'] || row['resp_rev'] || '').trim(),
    mejoras:           (row['Acciones de Mejora'] || row['mejoras'] || '').trim(),
    fecha_mejora:      parseDate(row['Fecha Compromiso Mejora'] || row['fecha_mejora']),
    estado_mejora:     (row['Estado de Mejora'] || row['estado_mejora'] || '').trim(),
    observaciones:     (row['Observaciones'] || row['observaciones'] || '').trim(),
  };

  procesos.push(proceso);

  // ── KPIs (hasta 3 por proceso) ─────────────────────────────────────────────
  const kpiDefs = [
    { n: row['KPI 1 – Nombre']||row['kpi1_nom'], m: row['KPI 1 – Meta']||row['kpi1_meta'], a: row['KPI 1 – Valor Actual']||row['kpi1_actual'], s: row['KPI 1 – Semáforo']||row['kpi1_semaforo'], f: row['KPI 1 – Frecuencia Med.']||row['kpi1_frec'] },
    { n: row['KPI 2 – Nombre']||row['kpi2_nom'], m: row['KPI 2 – Meta']||row['kpi2_meta'], a: row['KPI 2 – Valor Actual']||row['kpi2_actual'], s: row['KPI 2 – Semáforo']||row['kpi2_semaforo'], f: row['KPI 2 – Frecuencia Med.']||row['kpi2_frec'] },
    { n: row['KPI 3 – Nombre']||row['kpi3_nom'], m: row['KPI 3 – Meta']||row['kpi3_meta'], a: row['KPI 3 – Valor Actual']||row['kpi3_actual'], s: row['KPI 3 – Semáforo']||row['kpi3_semaforo'], f: row['KPI 3 – Frecuencia Med.']||row['kpi3_frec'] },
  ];

  kpiDefs.forEach((k, idx) => {
    if (!k.n || !String(k.n).trim()) return;
    const semaforoRaw = String(k.s || '').toLowerCase();
    const semaforo = semaforoRaw.includes('🔴') || semaforoRaw.includes('crít') || semaforoRaw === 'red' ? 'red'
                   : semaforoRaw.includes('🟡') || semaforoRaw.includes('alert') || semaforoRaw === 'yellow' ? 'yellow'
                   : 'green';
    kpis.push({
      proceso_id:    codigo,
      orden:         idx + 1,
      nombre:        String(k.n).trim(),
      meta:          String(k.m || '').trim(),
      actual:        String(k.a || '').trim(),
      semaforo,
      frecuencia_med:String(k.f || '').trim(),
    });
  });
}

// Pasar todo junto en una variable global para los siguientes nodos
$execution.customData.set('procesos', JSON.stringify(procesos));
$execution.customData.set('kpis', JSON.stringify(kpis));

console.log(`✅ Procesados: ${procesos.length} procesos, ${kpis.length} KPIs`);

// Retornar los procesos para el siguiente nodo
return procesos.map(p => ({ json: p }));

// Recuperar KPIs guardados en el nodo de transformación
const kpisJson = $execution.customData.get('kpis');
const kpis = JSON.parse(kpisJson || '[]');
console.log(`KPIs a sincronizar: ${kpis.length}`);
return kpis.map(k => ({ json: k }));

const procesados = $('node-upsert-proceso').all().length;
const kpisUpserted = $('node-upsert-kpi').all().length;
const now = new Date().toLocaleString('es-ES', { timeZone: 'America/La_Paz' });
console.log(`\n✅ Sincronización completada [${now}]`);
console.log(`   Procesos: ${procesados}`);
console.log(`   KPIs:     ${kpisUpserted}`);
return [{ json: { status: 'ok', procesados, kpisUpserted, timestamp: now } }];

const error = $input.first();
console.error('❌ Error en sincronización:', JSON.stringify(error.json, null, 2));
// Aquí podés agregar un nodo de notificación (Slack, email, Teams)
return [{ json: { status: 'error', details: error.json } }];
